package by.sorface.passport.web.security.configimport by.sorface.passport.web.config.options.*import by.sorface.passport.web.records.principals.DefaultPrincipalimport by.sorface.passport.web.security.config.Jwks.generateRsaimport by.sorface.passport.web.security.config.formlogin.JsonFormLoginFailureHandlerimport by.sorface.passport.web.security.config.formlogin.JsonUsernamePasswordAuthenticationFilterimport by.sorface.passport.web.security.config.formlogin.SessionRedirectSuccessHandlerimport by.sorface.passport.web.security.constants.WhitelistUrlsimport by.sorface.passport.web.security.extensions.jsonLoginimport by.sorface.passport.web.security.oauth2.services.AccountSessionServiceimport by.sorface.passport.web.security.oauth2.services.OAuth2UserDatabaseStrategyimport by.sorface.passport.web.security.oauth2.slo.DelegateLogoutSuccessHandlerimport by.sorface.passport.web.security.oauth2.slo.OidcPostRedirectLocationLogoutHandlerimport by.sorface.passport.web.security.oauth2.slo.OidcWebSessionLogoutHandlerimport by.sorface.passport.web.utils.LogicUtils.orimport com.nimbusds.jose.jwk.JWKSelectorimport com.nimbusds.jose.jwk.JWKSetimport com.nimbusds.jose.jwk.RSAKeyimport com.nimbusds.jose.jwk.source.JWKSourceimport com.nimbusds.jose.proc.SecurityContextimport jakarta.servlet.FilterChainimport jakarta.servlet.http.HttpServletRequestimport jakarta.servlet.http.HttpServletResponseimport org.springframework.context.annotation.Beanimport org.springframework.context.annotation.Configurationimport org.springframework.core.Orderedimport org.springframework.core.annotation.Orderimport org.springframework.http.HttpMethodimport org.springframework.http.ResponseCookie.ResponseCookieBuilderimport org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilderimport org.springframework.security.config.annotation.authentication.configuration.EnableGlobalAuthenticationimport org.springframework.security.config.annotation.method.configuration.EnableMethodSecurityimport org.springframework.security.config.annotation.web.builders.HttpSecurityimport org.springframework.security.config.annotation.web.configuration.EnableWebSecurityimport org.springframework.security.config.annotation.web.configurers.*import org.springframework.security.core.Authenticationimport org.springframework.security.crypto.bcrypt.BCryptPasswordEncoderimport org.springframework.security.crypto.password.PasswordEncoderimport org.springframework.security.oauth2.core.oidc.endpoint.OidcParameterNamesimport org.springframework.security.oauth2.jwt.JwtDecoderimport org.springframework.security.oauth2.jwt.JwtEncoderimport org.springframework.security.oauth2.jwt.NimbusJwtEncoderimport org.springframework.security.oauth2.server.authorization.OAuth2AuthorizationServiceimport org.springframework.security.oauth2.server.authorization.OAuth2TokenTypeimport org.springframework.security.oauth2.server.authorization.config.annotation.web.configuration.OAuth2AuthorizationServerConfigurationimport org.springframework.security.oauth2.server.authorization.config.annotation.web.configurers.OAuth2AuthorizationServerConfigurerimport org.springframework.security.oauth2.server.authorization.config.annotation.web.configurers.OidcConfigurerimport org.springframework.security.oauth2.server.authorization.config.annotation.web.configurers.OidcLogoutEndpointConfigurerimport org.springframework.security.oauth2.server.authorization.settings.AuthorizationServerSettingsimport org.springframework.security.oauth2.server.authorization.token.JwtEncodingContextimport org.springframework.security.oauth2.server.authorization.token.OAuth2TokenCustomizerimport org.springframework.security.web.SecurityFilterChainimport org.springframework.security.web.authentication.LoginUrlAuthenticationEntryPointimport org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilterimport org.springframework.security.web.authentication.logout.CookieClearingLogoutHandlerimport org.springframework.security.web.authentication.www.BasicAuthenticationFilterimport org.springframework.security.web.csrf.*import org.springframework.security.web.savedrequest.HttpSessionRequestCacheimport org.springframework.security.web.util.matcher.AntPathRequestMatcherimport org.springframework.session.web.http.CookieSerializerimport org.springframework.session.web.http.DefaultCookieSerializerimport org.springframework.web.filter.OncePerRequestFilterimport org.springframework.web.servlet.config.annotation.CorsRegistryimport org.springframework.web.servlet.config.annotation.WebMvcConfigurerimport java.security.KeyPairimport java.security.KeyPairGeneratorimport java.security.interfaces.RSAPrivateKeyimport java.security.interfaces.RSAPublicKeyimport java.util.*import java.util.function.Supplier@EnableWebSecurity(debug = true)@EnableMethodSecurity@EnableGlobalAuthentication@Configuration(proxyBeanMethods = false)class SecurityConfig(    private val accountSessionService: AccountSessionService,    private val authorizationService: OAuth2AuthorizationService,    private val oAuth2UserDatabaseStrategy: OAuth2UserDatabaseStrategy,    private val accessDeniedHandler: AccessDeniedHandler,    private val endpointProperties: EndpointProperties) {    @Bean    @Order(Ordered.HIGHEST_PRECEDENCE)    fun authServerSecurityFilterChain(        httpSecurity: HttpSecurity,        sessionCookieOptions: SessionCookieOptions    ): SecurityFilterChain {        OAuth2AuthorizationServerConfiguration.applyDefaultSecurity(httpSecurity)        httpSecurity            .getConfigurer(OAuth2AuthorizationServerConfigurer::class.java)            .oidc { oidcConfigurer: OidcConfigurer ->                oidcConfigurer.logoutEndpoint { logoutEndpointConfigurer: OidcLogoutEndpointConfigurer ->                    val delegateLogoutSuccessHandler = DelegateLogoutSuccessHandler(                        CookieClearingLogoutHandler(sessionCookieOptions.name, sessionCookieOptions.name),                        OidcWebSessionLogoutHandler(accountSessionService, authorizationService),                        OidcPostRedirectLocationLogoutHandler()                    )                    logoutEndpointConfigurer.logoutResponseHandler(delegateLogoutSuccessHandler)                }            }        httpSecurity.exceptionHandling { configurer ->            configurer.authenticationEntryPoint(LoginUrlAuthenticationEntryPoint(endpointProperties.uriPageSignIn))        }        return httpSecurity.build()    }    @Bean    @Throws(Exception::class)    fun defaultSecurityFilterChain(        httpSecurity: HttpSecurity,        sessionRedirectSuccessHandler: SessionRedirectSuccessHandler,        authenticationFailureHandler: JsonFormLoginFailureHandler,        jsonUnauthorizedAuthenticationEntryPoint: JsonUnauthorizedAuthenticationEntryPoint?,        cookieCsrfTokenRepository: CookieCsrfTokenRepository,        csrfTokenRequestHandler: CsrfTokenRequestHandler,        endpointProperties: EndpointProperties    ): SecurityFilterChain {        httpSecurity.getSharedObject(AuthenticationManagerBuilder::class.java)        return httpSecurity            .oauth2Login { oauth2LoginSpec ->                oauth2LoginSpec.userInfoEndpoint { userInfoEndpointSpec ->                    userInfoEndpointSpec.userService(                        oAuth2UserDatabaseStrategy                    )                }                oauth2LoginSpec.loginPage(endpointProperties.uriPageSignIn)                oauth2LoginSpec.successHandler(sessionRedirectSuccessHandler)                oauth2LoginSpec.failureHandler(authenticationFailureHandler)            }            .cors{}            .requestCache { httpSecurityRequestCacheConfigurer: RequestCacheConfigurer<HttpSecurity?> ->                val httpSessionRequestCache = HttpSessionRequestCache()                httpSessionRequestCache.setRequestMatcher(AntPathRequestMatcher("/oauth2/**"))                httpSecurityRequestCacheConfigurer.requestCache(httpSessionRequestCache)            }            .csrf { csrfSpec ->                val csrfAuthenticationStrategy = CsrfAuthenticationStrategy(cookieCsrfTokenRepository)                csrfSpec                    .ignoringRequestMatchers(                        AntPathRequestMatcher.antMatcher(HttpMethod.GET),                        AntPathRequestMatcher.antMatcher(HttpMethod.POST, endpointProperties.uriApiLogin)                    )                    .csrfTokenRepository(cookieCsrfTokenRepository)                    .csrfTokenRequestHandler(csrfTokenRequestHandler)                    .sessionAuthenticationStrategy(csrfAuthenticationStrategy)            }            .addFilterAfter(CsrfConfiguration.CsrfCookieFilter(), BasicAuthenticationFilter::class.java)            .addFilterAt(JsonUsernamePasswordAuthenticationFilter(), UsernamePasswordAuthenticationFilter::class.java)            .authorizeHttpRequests { authorizeHttpRequestsSpec ->                authorizeHttpRequestsSpec                    .requestMatchers(*WhitelistUrls.WHITE_LIST.patterns.toTypedArray()).permitAll()                    .requestMatchers(*WhitelistUrls.SIGN_UP.patterns.toTypedArray()).anonymous()                    .requestMatchers(HttpMethod.OPTIONS, *WhitelistUrls.toArray(WhitelistUrls.OPTION_REQUEST))                    .permitAll()                    .requestMatchers(HttpMethod.GET, *WhitelistUrls.toArray(WhitelistUrls.CSRF)).permitAll()                    .requestMatchers(HttpMethod.GET, *WhitelistUrls.toArray(WhitelistUrls.API_ACCOUNT)).permitAll()                    .requestMatchers(*WhitelistUrls.toArray()).permitAll()                    .anyRequest()                    .authenticated()            }            .oidcLogout { spec ->                spec.backChannel {}            }            .logout { logoutSpec -> logoutSpec.disable() }            .jsonLogin { jsonLoginSpec ->                jsonLoginSpec.loginPage(endpointProperties.uriPageSignIn)                jsonLoginSpec.loginProcessingUrl(endpointProperties.uriApiLogin)                jsonLoginSpec.successHandler(sessionRedirectSuccessHandler)                jsonLoginSpec.failureHandler(authenticationFailureHandler)            }            .exceptionHandling { exceptionHandlingSpec ->                exceptionHandlingSpec.accessDeniedHandler(accessDeniedHandler)                exceptionHandlingSpec.authenticationEntryPoint(jsonUnauthorizedAuthenticationEntryPoint)            }            .build()    }    @Bean    fun passwordEncoder(): PasswordEncoder = BCryptPasswordEncoder(10)    @Bean    fun jwtDecoder(jwkSource: JWKSource<SecurityContext?>?): JwtDecoder =        OAuth2AuthorizationServerConfiguration.jwtDecoder(jwkSource)    @Bean    fun jwtEncoder(jwkSource: JWKSource<SecurityContext?>?): JwtEncoder = NimbusJwtEncoder(jwkSource)    @Bean    fun jwkSource(): JWKSource<SecurityContext> {        val rsa = generateRsa()        val jwkSet = JWKSet(rsa)        return JWKSource { jwkSelector: JWKSelector, _ -> jwkSelector.select(jwkSet) }    }    @Bean    fun authorizationServerSettings(): AuthorizationServerSettings = AuthorizationServerSettings.builder()        .issuer(endpointProperties.issuer)        .build()}@Configurationclass CookieConfiguration {    @Bean    fun sessionCookieSerializer(sessionCookieOptions: SessionCookieOptions): CookieSerializer {        return sessionCookieOptions.run {            val serializer = DefaultCookieSerializer()            serializer.setCookieName(this.name)            serializer.setCookiePath(this.path)            serializer.setDomainNamePattern(this.domainPattern)            serializer.setUseHttpOnlyCookie(this.httpOnly)            this.sameSite.let { siteProperties ->                serializer.setSameSite(siteProperties.value)            }            serializer        }    }}@Configurationclass CsrfConfiguration {    @Bean    fun cookieCsrfTokenRepository(csrfCookieOptions: CsrfCookieOptions): CookieCsrfTokenRepository {        val cookieCsrfTokenRepository = CookieCsrfTokenRepository()        cookieCsrfTokenRepository.cookiePath = csrfCookieOptions.path        cookieCsrfTokenRepository.setCookieName(csrfCookieOptions.name)        cookieCsrfTokenRepository.setCookieCustomizer { cookieBuilder: ResponseCookieBuilder ->            cookieBuilder.httpOnly(csrfCookieOptions.httpOnly)            cookieBuilder.domain(csrfCookieOptions.domain)            cookieBuilder.secure(csrfCookieOptions.secure)        }        return cookieCsrfTokenRepository    }    @Bean    fun spaCsrfTokenRequestHandler(): CsrfTokenRequestHandler {        return SpaCsrfTokenRequestHandler(XorCsrfTokenRequestAttributeHandler())    }    open class SpaCsrfTokenRequestHandler(private val delegate: CsrfTokenRequestHandler) :        CsrfTokenRequestAttributeHandler() {        override fun handle(            request: HttpServletRequest,            response: HttpServletResponse,            csrfToken: Supplier<CsrfToken>        ) {            delegate.handle(request, response, csrfToken)        }        override fun resolveCsrfTokenValue(request: HttpServletRequest, csrfToken: CsrfToken): String? =            when {                request.getHeader(csrfToken.headerName)?.isNotBlank() == true -> super.resolveCsrfTokenValue(                    request,                    csrfToken                )                else -> delegate.resolveCsrfTokenValue(request, csrfToken)            }    }    open class CsrfCookieFilter : OncePerRequestFilter() {        public override fun doFilterInternal(            request: HttpServletRequest,            response: HttpServletResponse,            filterChain: FilterChain        ) {            val csrfToken = request.getAttribute("_csrf") as CsrfToken            csrfToken.token            filterChain.doFilter(request, response)        }    }}@Configurationclass CorsConfig(private val corsProperties: CorsProperties) {    companion object {        private const val SPLITERATOR: String = ";"    }    @Bean    fun cors() : WebMvcConfigurer {        return object : WebMvcConfigurer {            override fun addCorsMappings(registry: CorsRegistry) {                corsProperties.options.forEach { corsItem ->                    val allowedOrigins = corsItem.allowedOrigins?.split(SPLITERATOR) ?: listOf()                    val allowedMethods = corsItem.allowedMethods?.split(SPLITERATOR) ?: listOf()                    val allowedHeaders = corsItem.allowedHeaders?.split(SPLITERATOR) ?: listOf()                    val exposedHeaders = corsItem.exposedHeaders?.split(SPLITERATOR) ?: listOf()                    registry.addMapping(corsItem.pattern)                        .allowedOrigins(*allowedOrigins.toTypedArray())                        .allowedMethods(*allowedMethods.toTypedArray())                        .allowedHeaders(*allowedHeaders.toTypedArray())                        .exposedHeaders(*exposedHeaders.toTypedArray())                        .allowCredentials(corsItem.allowCredentials)                        .maxAge(corsItem.maxAge)                }            }        }    }}@Configuration(proxyBeanMethods = false)class IdTokenCustomizerConfig {    @Bean    fun tokenCustomizer(): OAuth2TokenCustomizer<JwtEncodingContext> =        OAuth2TokenCustomizer { context: JwtEncodingContext ->            if (or(                    OidcParameterNames.ID_TOKEN == context.tokenType.value,                    OAuth2TokenType.ACCESS_TOKEN == context.tokenType                )            ) {                context.claims.claims { claims: MutableMap<String?, Any?> -> claims.putAll(buildCustomClaims(context)) }            }        }    private fun buildCustomClaims(context: JwtEncodingContext): Map<String, Any?> {        val principal = context.getPrincipal<Authentication>().principal as DefaultPrincipal        val roles = principal.authorities.map { it.authority }.toSet()        return java.util.Map.of(CLAIMS_ROLES_NAME, roles, CLAIMS_USER_ID_NAME, principal.id)    }    companion object {        private const val CLAIMS_USER_ID_NAME = "principal-id"        private const val CLAIMS_ROLES_NAME = "roles"    }}object Jwks {    fun generateRsa(): RSAKey {        val keyPair = KeyGeneratorUtils.generateRsaKey(2048)        val publicKey = keyPair.public as RSAPublicKey        val privateKey = keyPair.private as RSAPrivateKey        return RSAKey.Builder(publicKey)            .privateKey(privateKey)            .keyID(UUID.randomUUID().toString())            .build()    }}object KeyGeneratorUtils {    fun generateRsaKey(keySize: Int): KeyPair {        val keyPair: KeyPair        try {            val keyPairGenerator = KeyPairGenerator.getInstance("RSA")            keyPairGenerator.initialize(keySize)            keyPair = keyPairGenerator.generateKeyPair()        } catch (ex: Exception) {            throw IllegalStateException(ex)        }        return keyPair    }}